  PaymentBackendClient(this.config, {http.Client? client})
      : _client = client ?? http.Client(),
        _log = PaymentLogger(config.debugLogging);

  Uri _u(String path) => config.backendBaseUrl.replace(
        path: '${config.backendBaseUrl.path.replaceAll(RegExp(r'/$'), '')}$path',
      );

  Future<Map<String, dynamic>> _postJson(
    String path,
    Map<String, dynamic> body, {
    Map<String, String>? headers,
  }) async {
    final uri = _u(path);
    final h = <String, String>{
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      if (config.appInstanceId != null) 'X-App-Instance-Id': config.appInstanceId!,
      ...?headers,
    };

    _log.d('POST $uri', body);

    final resp = await _client.post(uri, headers: h, body: jsonEncode(body));
    final text = resp.body;
    Map<String, dynamic> json;
    try {
      json = text.isEmpty ? <String, dynamic>{} : (jsonDecode(text) as Map<String, dynamic>);
    } catch (_) {
      throw PaymentException('backend_invalid_json', 'Invalid backend response', text);
    }

    if (resp.statusCode < 200 || resp.statusCode >= 300) {
      throw PaymentException(
        'backend_http_${resp.statusCode}',
        json['message']?.toString() ?? 'Backend error',
        json,
      );
    }
    return json;
  }

