        _log = PaymentLogger(config.debugLogging);

  Future<void> init({
    Set<String> iapProductIds = const <String>{},
    bool autoConsumeAndroid = true,
  }) async {
    final available = await _iap.isAvailable();
    isAvailable.value = available;

    if (available) {
      if (Platform.isIOS) {
        final iosPlatformAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
        await iosPlatformAddition.setDelegate(_StoreKitDelegate());
      }

      _purchaseSub?.cancel();
      _purchaseSub = _iap.purchaseStream.listen(
        (purchases) => _onPurchaseUpdates(purchases, autoConsumeAndroid: autoConsumeAndroid),
        onError: (e, st) => _log.e('purchaseStream error', e, st),
      );

      if (iapProductIds.isNotEmpty) {
        await loadCatalog(iapProductIds);
      }
    }
  }

  Future<void> dispose() async {
    if (Platform.isIOS) {
      try {
        final iosPlatformAddition = _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
        await iosPlatformAddition.setDelegate(null);
      } catch (_) {}
