  Future<void> loadCatalog(Set<String> productIds) async {
    if (!isAvailable.value) throw PaymentException('iap_unavailable', 'In-app purchases not available');
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      throw PaymentException('iap_query_failed', response.error!.message, response.error);
    }

    final items = response.productDetails.map((p) {
      return ProductCatalogItem(
        id: p.id,
        title: p.title,
        description: p.description,
        price: p.price,
        currencyCode: p.currencyCode,
        rawPrice: p.rawPrice.toString(),
        raw: <String, dynamic>{
          'currencySymbol': p.currencySymbol,
          'rawPrice': p.rawPrice.toString(),
        },
      );
    }).toList();

    catalog.value = items;
  }

  Future<PaymentResult> buyConsumable({
    required String productId,
    Map<String, dynamic>? metadata,
  }) async {
    if (!isAvailable.value) throw PaymentException('iap_unavailable', 'In-app purchases not available');

    final platform = Platform.isIOS ? 'ios' : 'android';
    final order = await backend.createIapOrder(
      productId: productId,
      platform: platform,
      metadata: metadata,
    );

    final orderId = order['orderId']?.toString();
    if (orderId == null || orderId.isEmpty) {
      throw PaymentException('backend_missing_order', 'Missing orderId from backend', order);
    }

    final productDetails = await _getProductDetails(productId);

    final purchaseParam = PurchaseParam(
      productDetails: productDetails,
      applicationUserName: order['applicationUserName']?.toString(),
    );

    final ok = await _iap.buyConsumable(
      purchaseParam: purchaseParam,
      autoConsume: Platform.isAndroid,
    );

    if (!ok) {
      final result = PaymentResult(
        provider: PaymentProviderType.inAppPurchase,
        status: PaymentStatus.failed,
        orderId: orderId,
        message: 'Purchase flow failed to start',
      );
      lastResult.value = result;
      return result;
    }

    final pending = PaymentResult(
      provider: PaymentProviderType.inAppPurchase,
      status: PaymentStatus.pending,
      orderId: orderId,
      message: 'Purchase initiated',
    );
    lastResult.value = pending;
    return pending;
  }

