  Future<ProductDetails> _getProductDetails(String productId) async {
    final cached = catalog.value.where((e) => e.id == productId).toList();
    if (cached.isNotEmpty) {
      final response = await _iap.queryProductDetails({productId});
      if (response.productDetails.isNotEmpty) return response.productDetails.first;
    }
    final response = await _iap.queryProductDetails({productId});
    if (response.error != null) {
      throw PaymentException('iap_query_failed', response.error!.message, response.error);
    }
    final pd = response.productDetails.firstWhere(
      (p) => p.id == productId,
      orElse: () => throw PaymentException('iap_product_not_found', 'Product not found: $productId'),
    );
    return pd;
  }

  Future<void> restorePurchases() async {
    if (!isAvailable.value) throw PaymentException('iap_unavailable', 'In-app purchases not available');
    await _iap.restorePurchases();
  }

  Future<void> _onPurchaseUpdates(
    List<PurchaseDetails> purchases, {
    required bool autoConsumeAndroid,
  }) async {
    for (final p in purchases) {
      try {
        _log.d('Purchase update', {
          'status': p.status.name,
          'productId': p.productID,
          'purchaseId': p.purchaseID,
          'pendingCompletePurchase': p.pendingCompletePurchase,
          'verificationDataSource': p.verificationData.source,
        });

        if (p.status == PurchaseStatus.pending) {
          lastResult.value = PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.pending,
            transactionId: p.purchaseID,
            message: 'Pending',
            raw: _purchaseToRaw(p),
          );
          continue;
        }

        if (p.status == PurchaseStatus.canceled) {
          final res = PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.canceled,
            transactionId: p.purchaseID,
            message: 'Canceled',
            raw: _purchaseToRaw(p),
          );
          lastResult.value = res;
          if (p.pendingCompletePurchase) await _iap.completePurchase(p);
          continue;
        }

        if (p.status == PurchaseStatus.error) {
          final res = PaymentResult(
            provider: PaymentProviderType.inAppPurchase,
            status: PaymentStatus.failed,
            transactionId: p.purchaseID,
            message: p.error?.message ?? 'Purchase error',
            raw: _purchaseToRaw(p),
          );
          lastResult.value = res;
          if (p.pendingCompletePurchase) await _iap.completePurchase(p);
          continue;
        }

        if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
          final platform = Platform.isIOS ? 'ios' : 'android';

          final payload = <String, dynamic>{
            'productId': p.productID,
            'purchaseId': p.purchaseID,
            'transactionDate': p.transactionDate,
            'status': p.status.name,
            'verificationData': {
              'source': p.verificationData.source,
              'serverVerificationData': p.verificationData.serverVerificationData,
              'localVerificationData': p.verificationData.localVerificationData,
            },
          };

          if (Platform.isAndroid) {
            final androidDetails = p as GooglePlayPurchaseDetails;
            payload['billingClientPurchase'] = androidDetails.billingClientPurchase.toJson();
            if (!autoConsumeAndroid) {
              payload['isAcknowledged'] = androidDetails.billingClientPurchase.isAcknowledged;
            }
          } else if (Platform.isIOS) {
            payload['skPaymentTransaction'] = (p as AppStorePurchaseDetails).skPaymentTransaction?.toMap();
          }

          final orderId = _extractOrderIdFromApplicationUserName(p) ?? '';
          final verify = await backend.verifyIapReceipt(
            orderId: orderId,
            platform: platform,
            payload: payload,
          );

          final status = (verify['status']?.toString() ?? '').toLowerCase();
          final succeeded = status == 'succeeded' || status == 'success' || verify['ok'] == true;

          if (succeeded) {
            if (Platform.isAndroid) {
              final androidAddition = _iap.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
              try {
                await androidAddition.consumePurchase(p);
              } catch (_) {}
            }

            final res = PaymentResult(
              provider: PaymentProviderType.inAppPurchase,
              status: PaymentStatus.succeeded,
              transactionId: p.purchaseID,
              orderId: verify['orderId']?.toString() ?? orderId,
              receiptOrToken: p.verificationData.serverVerificationData,
              message: 'Verified',
              raw: verify,
            );
            lastResult.value = res;
          } else {
            final res = PaymentResult(
              provider: PaymentProviderType.inAppPurchase,
              status: PaymentStatus.failed,
              transactionId: p.purchaseID,
              orderId: verify['orderId']?.toString() ?? orderId,
              receiptOrToken: p.verificationData.serverVerificationData,
              message: verify['message']?.toString() ?? 'Verification failed',
              raw: verify,
            );
            lastResult.value = res;
          }

          if (p.pendingCompletePurchase) {
            await _iap.completePurchase(p);
          }
        }
      } catch (e, st) {
        _log.e('Failed handling purchase update', e, st);
        try {
          if (p.pendingCompletePurchase) await _iap.completePurchase(p);
        } catch (_) {}
        lastResult.value = PaymentResult(
          provider: PaymentProviderType.inAppPurchase,
          status: PaymentStatus.failed,
          transactionId: p.purchaseID,
          message: e is PaymentException ? e.message : 'Unhandled purchase processing error',
          raw: {'error': e.toString()},
        );
      }
    }
  }

  Map<String, dynamic> _purchaseToRaw(PurchaseDetails p) {
    return <String, dynamic>{
      'productId': p.productID,
      'purchaseId': p.purchaseID,
      'transactionDate': p.transactionDate,
      'status': p.status.name,
      'pendingCompletePurchase': p.pendingCompletePurchase,
      'error': p.error == null
          ? null
          : {
              'code': p.error!.code,
              'message': p.error!.message,
              'details': p.error!.details?.toString(),
            },
      'verificationData': {
        'source': p.verificationData.source,
        'serverVerificationData': p.verificationData.serverVerificationData,
        'localVerificationData': p.verificationData.localVerificationData,
      },
    };
  }

  String? _extractOrderIdFromApplicationUserName(PurchaseDetails p) {
    final name = p.applicationUserName;
    if (name == null || name.isEmpty) return null;
    return name;
  }

  Future<PaymentResult> payWithWallet({
    required String walletType,
    required WalletPaymentRequest request,
  }) async {
    final available = await walletBridge.isWalletAvailable(walletType);
    if (!available) {
      final res = PaymentResult(
        provider: PaymentProviderType.mobileWallet,
        status: PaymentStatus.failed,
        message: '$walletType not available',
      );
      lastResult.value = res;
      return res;
    }

    final intent = await backend.createWalletPaymentIntent(request: request, walletType: walletType);
    final intentId = intent['intentId']?.toString();
    if (intentId == null || intentId.isEmpty) {
      throw PaymentException('backend_missing_intent', 'Missing intentId from backend', intent);
    }

    final walletPayload = await walletBridge.presentWalletSheet(
      walletType: walletType,
      clientSecretOrToken: intent,
    );

    final confirm = await backend.confirmWalletPayment(
      intentId: intentId,
      walletType: walletType,
      walletPayload: walletPayload,
    );

    final statusStr = (confirm['status']?.toString() ?? '').toLowerCase();
    final status = _mapStatus(statusStr);

    final res = PaymentResult(
      provider: PaymentProviderType.mobileWallet,
      status: status,
      transactionId: confirm['transactionId']?.toString(),
      orderId: confirm['orderId']?.toString(),
      receiptOrToken: confirm['receipt']?.toString() ?? confirm['token']?.toString(),
      message: confirm['message']?.toString(),
      raw: confirm,
    );
    lastResult.value = res;
    return res;
  }

  Future<PaymentResult> payWithCardGateway({
    required CardPaymentIntentRequest request,
    required Future<Map<String, dynamic>> Function(Map<String, dynamic> clientData) collectAndConfirm,
  }) async {
    final intent = await backend.createCardPaymentIntent(request: request);
    final intentId = intent['intentId']?.toString();
    if (intentId == null || intentId.isEmpty) {
      throw PaymentException('backend_missing_intent', 'Missing intentId from backend', intent);
    }

    final confirmationPayload = await collectAndConfirm(intent);

    final confirm = await backend.confirmCardPayment(
      intentId: intentId,
      confirmationPayload: confirmationPayload,
    );

    final statusStr = (confirm['status']?.toString() ?? '').toLowerCase();
    final status = _mapStatus(statusStr);

    final res = PaymentResult(
      provider: PaymentProviderType.cardGateway,
      status: status,
      transactionId: confirm['transactionId']?.toString(),
      orderId: confirm['orderId']?.toString(),
      receiptOrToken: confirm['receipt']?.toString() ?? confirm['token']?.toString(),
      message: confirm['message']?.toString(),
      raw: confirm,
    );
    lastResult.value = res;
    return res;
  }

  PaymentStatus _mapStatus(String statusStr) {
    switch (statusStr) {
      case 'succeeded':
      case 'success':
        return PaymentStatus.succeeded;
      case 'requires_action':
      case 'requiresaction':
        return PaymentStatus.requiresAction;
      case 'canceled':
      case 'cancelled':
        return PaymentStatus.canceled;
      case 'refunded':
        return PaymentStatus.refunded;
      case 'failed':
      case 'error':
        return PaymentStatus.failed;
      case 'pending':
      default:
        return PaymentStatus.pending;
    }
  }
}

class _StoreKitDelegate implements SKPaymentQueueDelegateWrapper {
  @override
  bool shouldContinueTransaction(SKPaymentTransactionWrapper transaction, SKStorefrontWrapper storefront) {
    return true;
  }

  @override
  bool shouldShowPriceConsent() => false;
}

extension _SkPaymentTransactionMap on SKPaymentTransactionWrapper {
  Map<String, dynamic> toMap() => <String, dynamic>{
        'transactionIdentifier': transactionIdentifier,
        'transactionDate': transactionDate?.toIso8601String(),
        'transactionState': transactionState.toString(),
        'payment': {
          'productIdentifier': payment.productIdentifier,
          'applicationUsername': payment.applicationUsername,
          'quantity': payment.quantity,
          'requestData': payment.requestData,
          'simulatesAskToBuyInSandbox': payment.simulatesAskToBuyInSandbox,
        },
        'error': error == null
            ? null
            : {
                'code': error!.code,
                'domain': error!.domain,
                'userInfo': error!.userInfo,
              },
      };
}

class PaymentSecurity {
  PaymentSecurity._();

  static void assertNoCardDataStored(Map<String, dynamic> data) {
    const forbiddenKeys = <String>{
      'cardNumber',
      'cvc',
      'cvv',
      'pan',
      'expiry',
      'expMonth',
      'expYear',
      'track1',
      'track2',
      'magstripe',
      'pin',
    };
    for (final k in data.keys) {
      if (forbiddenKeys.contains(k)) {
        throw PaymentException('pci_violation', 'Forbidden card data key detected: $k');
      }
    }
  }

  static Map<String, dynamic> redactSensitive(Map<String, dynamic> data) {
    final out = <String, dynamic>{};
    for (final e in data.entries) {
      final key = e.key.toLowerCase();
      if (key.contains('secret') || key.contains('token') || key.contains('receipt') || key.contains('verification')) {
        out[e.key] = '[REDACTED]';
      } else {
        out[e.key] = e.value;
      }
    }
    return out;
  }
}

class PaymentsFacade {
  final PaymentModule module;
  PaymentsFacade(this.module);

  Future<void> initialize({
    required Set<String> iapProductIds,
  }) =>
      module.init(iapProductIds: iapProductIds);

  Future<List<ProductCatalogItem>> fetchCatalog() async => module.catalog.value;

  Future<PaymentResult> purchaseProduct(String productId, {bool consumable = true, Map<String, dynamic>? metadata}) {
    return consumable
        ? module.buyConsumable(productId: productId, metadata: metadata)
        : module.buyNonConsumable(productId: productId, metadata: metadata);
  }

  Future<PaymentResult> payApplePayOrGooglePay({
    required String walletType,
    required WalletPaymentRequest request,
  }) =>
      module.payWithWallet(walletType: walletType, request: request);

  Future<PaymentResult> payWithGatewayCard({
    required CardPaymentIntentRequest request,
    required Future<Map<String, dynamic>> Function(Map<String, dynamic> clientData) collectAndConfirm,
  }) =>
      module.payWithCardGateway(request: request, collectAndConfirm: (clientData) async {
        PaymentSecurity.assertNoCardDataStored(clientData);
        final payload = await collectAndConfirm(clientData);
        PaymentSecurity.assertNoCardDataStored(payload);
        return payload;
      });
}